using MVZ2.Vanilla.RandomChina;
using MVZ2Logic.Blueprints;
using MVZ2Logic.Entities;
using MVZ2Logic.Level;
using PVZEngine;
using PVZEngine.Armors;
using PVZEngine.Buffs;
using PVZEngine.Entities;
using PVZEngine.Level;
using Tools;

namespace MVZ2.GameContent.RandomChinaEvents
{
    [RandomChinaEventDefinition(VanillaRandomChinaEventNames.wheelOfFortune)]
    public class WheelOfFortuneEvent : RandomChinaEventDefinition
    {
        public WheelOfFortuneEvent(string nsp, string path) : base(nsp, path, NAME, DESCRIPTION)
        {
        }
        public override void Run(Entity contraption, RandomGenerator rng)
        {
            var level = contraption.Level;
            for (int i = 0; i < COUNT; i++)
            {
                var spawnParams = new SpawnParams();
                var contraptionID = level.GetRandomContraptionFromPool(rng);
                var blueprintID = LogicBlueprintID.FromEntity(contraptionID);
                spawnParams.SetProperty(VanillaPickupProps.CONTENT_ID, blueprintID);
                contraption.Produce(VanillaPickupID.blueprintPickup, spawnParams);
            }
            contraption.PlaySound(VanillaSoundID.arcaneIntellect);
        }
        [TranslateMsg("随机瓷器事件名称", VanillaStrings.CONTEXT_RANDOM_CHINA_EVENT_NAME)]
        public const string NAME = "X-命运之轮";
        [TranslateMsg("随机瓷器事件描述", VanillaStrings.CONTEXT_RANDOM_CHINA_EVENT_DESCRIPTION)]
        public const string DESCRIPTION = "生成3张随机器械的蓝图";
        public const int COUNT = 3;
    }
}
